InterfaceAsPlainText.xhtml:
FUNCTION_BLOCK FB_RingData
VAR_INPUT
    bTrigger            : BOOL;                     
    aValues             : ARRAY[1..100] OF REAL;    
    nOversamples        : INT;                      

    // --- Configuration ---
    sFileDir            : STRING := 'C:\RingData\';       
    nMaxTrigCycles      : UDINT := 100;                   
    tMaxBatchTime       : TIME := T#60M;                  
    tIdleTimeout        : TIME := T#30M;                  

    // --- Metadata ---
    stBatchInfo         : ST_BatchMetadata;         
    stSensorInfo        : ST_SensorMetadata;        
END_VAR
VAR_OUTPUT
    bBusy               : BOOL;                     
    bError              : BOOL;                     
    nErrorID            : UDINT;  

    // Status Monitoring
    nCurrentBatchCount  : UDINT;
    tCurrentBatchTime   : TIME;
END_VAR
VAR
    // Triggers
    rTrig               : R_TRIG;
    fTrig               : F_TRIG;

    // State Flags
    bIsRecording        : BOOL;
    bIsSaving           : BOOL;

    // Data Buffering
    aDataBuffer         : ARRAY[0..99999] OF REAL; 
    nDataCount          : UDINT := 0;
    fInternalMax        : REAL;

    // Batch Tracking
    tBatchStartTime     : TIME;
    bBatchActive        : BOOL;

    // Timers
    fbIdleTimer         : TON;

    // Time & Strings
    nDcTime64           : T_DCTIME64;    
    sStartTimestamp     : STRING;        
    sFileName           : STRING(255);
	sTempTime			: LREAL;

    // JSON & File IO
    fbJsonWriter        : FB_JsonSaxPrettyWriter;
    sJsonDoc            : STRING(2000000); 
    nJsonLen            : UDINT;

    fbCreateDir         : FB_CreateDir; // Added to ensure folder exists
    fbFileOpen          : FB_FileOpen;
    fbFileWrite         : FB_FileWrite;
    fbFileClose         : FB_FileClose;
    nWriteState         : INT := 0;
    hFileHandle         : UINT := 0;

    j                   : INT;
    k                   : UDINT;
END_VAR

