    nWriteState         : INT := 0;
    hFileHandle         : UINT := 0;

    j                   : INT;
    k                   : UDINT;
END_VAR

ST.xhtml:
// Edge Detection
rTrig(CLK := bTrigger);
fTrig(CLK := bTrigger);

// ---------------------------------------------------------
// 1. Idle Timeout Logic 
//    Resets batch if machine is idle too long
// ---------------------------------------------------------
fbIdleTimer(IN := NOT bTrigger AND NOT bIsSaving AND bBatchActive, PT := tIdleTimeout);

IF fbIdleTimer.Q THEN
    nCurrentBatchCount := 0;
    tCurrentBatchTime  := T#0S;
    bBatchActive       := FALSE;
    nDataCount         := 0;
END_IF

// ---------------------------------------------------------
// 2. Trigger ON (Start Stroke)
// ---------------------------------------------------------
IF rTrig.Q THEN
    // Initialize Batch Time on First Stroke
    IF NOT bBatchActive OR (nCurrentBatchCount = 0) THEN
        tBatchStartTime := TIME();
        bBatchActive    := TRUE;
    END_IF

    // Reset Buffer for this specific stroke
    nDataCount := 0;
    bIsRecording := TRUE;
    bError := FALSE;
    nErrorID := 0;
    fInternalMax := -1.0E38; 

    // Capture High-Precision DC Time
    nDcTime64 := F_GetCurDcTaskTime64();
    sStartTimestamp := LEFT(DCTIME64_TO_STRING(nDcTime64),23);
END_IF

// ---------------------------------------------------------
// 3. Recording Phase
// ---------------------------------------------------------
IF bIsRecording THEN
    IF nOversamples <= 0 THEN nOversamples := 1; END_IF

    FOR j := 1 TO nOversamples DO
        IF nDataCount <= 99999 THEN 
            aDataBuffer[nDataCount] := aValues[j];
            IF aValues[j] > fInternalMax THEN fInternalMax := aValues[j]; END_IF
            nDataCount := nDataCount + 1;
        ELSE
            bIsRecording := FALSE;
            nErrorID := 1; // Buffer Overflow
            bError := TRUE;
        END_IF
    END_FOR
END_IF

// ---------------------------------------------------------
// 4. Trigger OFF (End Stroke) -> Check Batch Save
// ---------------------------------------------------------
IF fTrig.Q AND bIsRecording THEN
    bIsRecording := FALSE;

    // Update Counts
    nCurrentBatchCount := nCurrentBatchCount + 1;

    // Update Batch Duration (Wall Clock Time)
    tCurrentBatchTime := TIME() - tBatchStartTime;

    // Check Save Conditions
    IF (nCurrentBatchCount >= nMaxTrigCycles) OR (tCurrentBatchTime >= tMaxBatchTime) THEN

        // Prepare Save
        M_JsonGenerate();

		// Generate the Filename
        sFileName := M_Filename(); 

        nWriteState := 1;
        bIsSaving   := TRUE;

        // Reset Batch Counters immediately
        nCurrentBatchCount := 0;
        tCurrentBatchTime  := T#0S;
        bBatchActive       := FALSE;
    END_IF
END_IF

// ---------------------------------------------------------
// 5. File IO State Machine
// ---------------------------------------------------------
CASE nWriteState OF
    0: // Idle
        ; 

    1: // Create Directory (Idempotent)
        fbCreateDir(bExecute := TRUE, sPathName := sFileDir);
        IF NOT fbCreateDir.bBusy THEN
            // We ignore error 1803 (Dir already exists)
            fbCreateDir(bExecute := FALSE); 
            nWriteState := 2;
        END_IF

    2: // Open File
        fbFileOpen(bExecute := TRUE, sPathName := sFileName, nMode := FOPEN_MODEWRITE OR FOPEN_MODETEXT);
        IF NOT fbFileOpen.bBusy THEN
            IF NOT fbFileOpen.bError THEN
                hFileHandle := fbFileOpen.hFile;
                nWriteState := 3;
            ELSE
                nErrorID := fbFileOpen.nErrId;
                bError := TRUE;
                nWriteState := 0;
                bIsSaving := FALSE;
            END_IF
            fbFileOpen(bExecute := FALSE);
        END_IF

    3: // Write Content
        fbFileWrite(bExecute := TRUE, hFile := hFileHandle, pWriteBuff := ADR(sJsonDoc), cbWriteLen := nJsonLen);
        IF NOT fbFileWrite.bBusy THEN
            IF fbFileWrite.bError THEN
                nErrorID := fbFileWrite.nErrId;
                bError := TRUE;
            END_IF
            nWriteState := 4;
            fbFileWrite(bExecute := FALSE);
        END_IF

    4: // Close File
        fbFileClose(bExecute := TRUE, hFile := hFileHandle);
        IF NOT fbFileClose.bBusy THEN
            hFileHandle := 0;
            nWriteState := 0;
            bIsSaving   := FALSE;
            fbFileClose(bExecute := FALSE);
        END_IF
END_CASE

bBusy := bIsRecording OR bIsSaving;

InterfaceAsPlainText.xhtml:
METHOD PRIVATE M_Filename : STRING
VAR
    sTimeStr : STRING;
    sTemp    : STRING;
END_VAR

ST.xhtml:
    sTimeStr := LEFT(sStartTimestamp, 19); 
    sTimeStr := REPLACE(sTimeStr, '-', 1, 14); 
    sTimeStr := REPLACE(sTimeStr, '-', 1, 17); 

    sTemp := CONCAT(sFileDir, stSensorInfo.sInputModule);
    sTemp := CONCAT(sTemp, '_');
    sTemp := CONCAT(sTemp, MID(sTimeStr, 19, 1)); 
    sTemp := CONCAT(sTemp, '.json');

	// Assign to the correct Method Name
    M_Filename := sTemp;

InterfaceAsPlainText.xhtml:
METHOD PRIVATE M_Filename : STRING
VAR
    sTimeStr : STRING;
    sTemp    : STRING;
END_VAR

ST.xhtml:
fbJsonWriter.ResetDocument();
fbJsonWriter.SetIndent(32, 2); 
fbJsonWriter.SetMaxDecimalPlaces(4); 
fbJsonWriter.StartObject(); 

    // ---------------------------------------------------------
    // 1. BATCH METADATA (Updated from ST_BatchMetadata)
    // ---------------------------------------------------------
    fbJsonWriter.AddKey('batch_metadata');
    fbJsonWriter.StartObject(); 
        fbJsonWriter.AddKeyString('order_sap', stBatchInfo.sOrderNumberSAP);
        fbJsonWriter.AddKeyString('factory', stBatchInfo.sFactory);
        fbJsonWriter.AddKey('department'); fbJsonWriter.AddDint(stBatchInfo.nDepartment);
        fbJsonWriter.AddKey('workcenter'); fbJsonWriter.AddDint(stBatchInfo.nWorkcenter);
        fbJsonWriter.AddKeyString('equipment_id', stBatchInfo.sEquipmentId);

        // Time Info
        fbJsonWriter.AddKeyString('trigger_start_time', sStartTimestamp);
        fbJsonWriter.AddKey('batch_accumulated_count'); fbJsonWriter.AddUdint(nCurrentBatchCount);
    fbJsonWriter.EndObject(); 

    // ---------------------------------------------------------
    // 2. SENSOR METADATA (Updated from ST_SensorMetadata)
    // ---------------------------------------------------------
    fbJsonWriter.AddKey('sensor_metadata');
    fbJsonWriter.StartObject(); 
        fbJsonWriter.AddKeyString('module', stSensorInfo.sInputModule);
        fbJsonWriter.AddKeyString('channel_name', stSensorInfo.sChannelName);
        fbJsonWriter.AddKeyString('channel_type', stSensorInfo.sChannelType);
        fbJsonWriter.AddKeyString('sensor_type', stSensorInfo.sSensorType);
        fbJsonWriter.AddKeyString('unit', stSensorInfo.sSensorUnit);
        fbJsonWriter.AddKey('increment_s'); fbJsonWriter.AddLreal(stSensorInfo.fIncrement);

        // Stats
        fbJsonWriter.AddKey('total_samples'); fbJsonWriter.AddUdint(nDataCount);
        fbJsonWriter.AddKey('max_peak'); fbJsonWriter.AddReal(fInternalMax);
    fbJsonWriter.EndObject(); 

    // ---------------------------------------------------------
    // 3. SAMPLES
    // ---------------------------------------------------------
    fbJsonWriter.AddKey('samples');
    fbJsonWriter.StartArray(); 
        IF nDataCount > 0 THEN
            FOR i := 0 TO (nDataCount - 1) DO
                fbJsonWriter.AddReal(aDataBuffer[i]);
            END_FOR
        END_IF
    fbJsonWriter.EndArray(); 
fbJsonWriter.EndObject(); 

nJsonLen := fbJsonWriter.CopyDocument(sJsonDoc, SIZEOF(sJsonDoc));
IF nJsonLen > 0 THEN nJsonLen := nJsonLen - 1; END_IF

